  ('elementary-8b44517b-moex-00537', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '依民國108年1月4日修正後的法院組織法，關於最高法院判例的適用，下列敘述何者正確？', '["無裁判全文可資查考之最高法院判例，停止適用", "無裁判全文可資查考之最高法院判例，其效力與未經選編為判例之最高法院裁判相同", "最高法院判例，無論有無裁判全文可資查考，均停止適用", "有裁判全文可資查考之最高法院判例，其效力位階高於未經選編為判例之最高法院裁判"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
