  ('elementary-8b44517b-moex-00539', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '行政機關可在數個合法、可行的途徑中選擇其認為最適合、最可以達成行政目的之方法，此種原則 為：', '["行政一體", "裁量", "事實之涵攝", "一事不再理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00540', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '關於自律規則，下列敘述何者錯誤？', '["自律規則係地方立法機關基於議會自律權而來，性質上為議會的內部事項規範", "與地方居民之權利義務相關之事項，亦得以自律規則定之", "自律規則除法律或自治條例另有規定外，原則上係由各該立法機關發布，並且須報各該上級政府 備查", "自律規則不得牴觸上級自治法規"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00541', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '修正法規時，如欲廢止或增加少數條文時，應為如何之處理？', '["不保留所廢條文之條次", "保留所廢條文之內容，且須註明「刪除」二字", "得將增加之條文，列在適當條文之後，冠以前條「之一」、「之二」等條次", "增加編或章時，不得冠以「之一」、「之二」等編或章次"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00542', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '依司法院憲法解釋意旨，下列何者為憲法中具有本質之重要性，即便修憲亦不可更動者？', '["雙首長制", "權力分立與制衡", "國家固有疆域", "修憲程序"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
