  ('elementary-8b44517b-moex-00544', 'elementary-8b44517b', 'elementary-8b44517b-moex-112-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '國立警察大學碩士班入學之招生簡章，限制有色盲者不得報考。依司法院憲法解釋意旨，該規定所 涉及之基本權，下列敘述何者最正確？', '["該規定對於憲法第21條保障人民受教育權造成限制", "該規定對於大學自治造成限制", "大法官採較嚴格審查標準予以審查", "該規定以生理特徵為分類標準，是違憲之差別待遇"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:32+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
